# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import subprocess
import os
import json
from google.cloud import storage


def process_image(event, context):
    """Cloud Function triggered by Cloud Storage event to convert images using ImageMagick.
    
    Args:
        event (dict): The Cloud Storage event payload.
        context (google.cloud.functions.Context): The event context.
    """
    bucket_name = event['bucket']
    file_name = event['name']
    metageneration = event.get('metageneration', '')
    content_type = event.get('contentType', '')
    
    print(f"Processing file: {file_name} from bucket: {bucket_name}")
    print(f"Content type: {content_type}")
    
    # Validate that the file is an image
    valid_image_types = ['image/jpeg', 'image/png', 'image/gif', 'image/tiff', 'image/bmp', 'image/webp']
    if content_type not in valid_image_types:
        print(f"Skipping non-image file: {file_name} with content type: {content_type}")
        return
    
    # Extract conversion options from custom metadata
    metadata = event.get('metadata', {}) or {}
    
    output_format = metadata.get('output_format', 'png')
    resize = metadata.get('resize', '')
    quality = metadata.get('quality', '')
    rotate = metadata.get('rotate', '')
    grayscale = metadata.get('grayscale', 'false')
    blur = metadata.get('blur', '')
    strip_metadata = metadata.get('strip', 'false')
    crop = metadata.get('crop', '')
    output_bucket = metadata.get('output_bucket', bucket_name)
    output_prefix = metadata.get('output_prefix', 'converted/')
    
    # Prevent infinite loops - skip already converted files
    if file_name.startswith(output_prefix):
        print(f"Skipping already converted file: {file_name}")
        return
    
    # Initialize Cloud Storage client
    storage_client = storage.Client()
    source_bucket = storage_client.bucket(bucket_name)
    source_blob = source_bucket.blob(file_name)
    
    # Create temp file paths
    tmp_dir = '/tmp'
    base_name = os.path.splitext(os.path.basename(file_name))[0]
    input_extension = os.path.splitext(file_name)[1]
    input_path = os.path.join(tmp_dir, f"input_{base_name}{input_extension}")
    output_filename = f"{base_name}.{output_format}"
    output_path = os.path.join(tmp_dir, f"output_{output_filename}")
    
    try:
        # Download the source image
        print(f"Downloading {file_name} to {input_path}")
        source_blob.download_to_filename(input_path)
        
        # Build the ImageMagick convert command
        convert_cmd = ['convert', input_path]
        
        # Apply conversion options from metadata
        if resize:
            # e.g., "800x600", "50%", "800x600!"
            convert_cmd.extend(['-resize', resize])
            print(f"Applying resize: {resize}")
        
        if quality:
            # e.g., "85" for JPEG quality
            convert_cmd.extend(['-quality', quality])
            print(f"Applying quality: {quality}")
        
        if rotate:
            # e.g., "90", "180", "270"
            convert_cmd.extend(['-rotate', rotate])
            print(f"Applying rotation: {rotate}")
        
        if grayscale.lower() == 'true':
            convert_cmd.extend(['-colorspace', 'Gray'])
            print("Applying grayscale conversion")
        
        if blur:
            # e.g., "0x8" for Gaussian blur
            convert_cmd.extend(['-blur', blur])
            print(f"Applying blur: {blur}")
        
        if strip_metadata.lower() == 'true':
            convert_cmd.append('-strip')
            print("Stripping metadata")
        
        if crop:
            # e.g., "800x600+0+0"
            convert_cmd.extend(['-crop', crop])
            print(f"Applying crop: {crop}")
        
        # Add output path
        convert_cmd.append(output_path)
        
        # Sanitize command parameters to prevent command injection
        for param in convert_cmd:
            if any(dangerous_char in param for dangerous_char in [';', '|', '&', '$', '`', '\n', '\r']):
                print(f"Error: Potentially dangerous character detected in parameter: {param}")
                return
        
        print(f"Executing command: {' '.join(convert_cmd)}")
        
        # Execute the ImageMagick convert command
        return_code = subprocess.call(convert_cmd, timeout=300)
        
        if return_code != 0:
            print(f"Error: ImageMagick convert command failed with return code {return_code}")
            raise RuntimeError(f"ImageMagick convert failed with return code {return_code}")
        
        print(f"Conversion successful. Output file: {output_path}")
        
        # Verify output file exists
        if not os.path.exists(output_path):
            raise FileNotFoundError(f"Output file not found: {output_path}")
        
        output_file_size = os.path.getsize(output_path)
        print(f"Output file size: {output_file_size} bytes")
        
        # Upload the converted image to the destination bucket
        dest_bucket = storage_client.bucket(output_bucket)
        dest_blob_name = f"{output_prefix}{output_filename}"
        dest_blob = dest_bucket.blob(dest_blob_name)
        
        # Determine output content type
        format_to_content_type = {
            'png': 'image/png',
            'jpg': 'image/jpeg',
            'jpeg': 'image/jpeg',
            'gif': 'image/gif',
            'tiff': 'image/tiff',
            'bmp': 'image/bmp',
            'webp': 'image/webp',
            'pdf': 'application/pdf',
        }
        output_content_type = format_to_content_type.get(output_format.lower(), 'application/octet-stream')
        
        # Set metadata on the output file
        dest_blob.metadata = {
            'source_file': file_name,
            'source_bucket': bucket_name,
            'conversion_options': json.dumps({
                'output_format': output_format,
                'resize': resize,
                'quality': quality,
                'rotate': rotate,
                'grayscale': grayscale,
                'blur': blur,
                'strip': strip_metadata,
                'crop': crop,
            }),
            'processed': 'true'
        }
        
        print(f"Uploading converted image to gs://{output_bucket}/{dest_blob_name}")
        dest_blob.upload_from_filename(output_path, content_type=output_content_type)
        
        print(f"Successfully processed {file_name} -> {dest_blob_name}")
        
    except subprocess.TimeoutExpired:
        print(f"Error: ImageMagick conversion timed out for file: {file_name}")
        raise
    except Exception as e:
        print(f"Error processing file {file_name}: {str(e)}")
        raise
    finally:
        # Clean up temporary files
        for tmp_file in [input_path, output_path]:
            if os.path.exists(tmp_file):
                os.remove(tmp_file)
                print(f"Cleaned up temp file: {tmp_file}")